import pytest
from validation.email_validator import EmailValidator
def test_validate_valid_email():
    assert EmailValidator.validate('test@example.com') == True
def test_validate_invalid_email():
    assert EmailValidator.validate('invalid-email') == False
def test_validate_non_string_input():
    assert EmailValidator.validate(12345) == False

import pytest
from validation.phone_number_formatter import PhoneNumberFormatter
def test_format_valid_phone_number():
    assert PhoneNumberFormatter.format('(123) 456-7890') == '(123) 456-7890'
def test_format_phone_number_with_spaces():
    assert PhoneNumberFormatter.format('123 456 7890') == '(123) 456-7890'
def test_format_phone_number_with_dashes():
    assert PhoneNumberFormatter.format('123-456-7890') == '(123) 456-7890'
def test_format_invalid_phone_number():
    assert PhoneNumberFormatter.format('12345') == None
def test_format_non_string_input():
    assert PhoneNumberFormatter.format(1234567890) == None

